chrome.action.onClicked.addListener(t=>{if(t.url,!t.id||!t.url)return;let e;try{e=new URL(t.url)}catch{return}const n=e.protocol==="https:"&&(e.hostname==="www.walmart.com"||e.hostname.endsWith(".walmart.com")),o=e.pathname.startsWith("/orders/")||e.pathname.startsWith("/account/purchase-history");if(!n){chrome.tabs.create({url:chrome.runtime.getURL("index.html")});return}if(!o){console.warn("[WalmartSplit] Not on an order page. Opening app without scraping."),chrome.tabs.create({url:chrome.runtime.getURL("index.html")});return}chrome.tabs.sendMessage(t.id,{action:"extract_receipt"},()=>{if(chrome.runtime.lastError){chrome.runtime.lastError.message;const r=chrome.runtime.getManifest().content_scripts?.[0]?.js;r&&t.id&&chrome.scripting.executeScript({target:{tabId:t.id},files:r}).then(()=>{setTimeout(()=>{chrome.tabs.sendMessage(t.id,{action:"extract_receipt"})},100)}).catch(c=>{console.error("[WalmartSplit] Failed to inject content script:",c)})}})});
